SELECT Sum(Val([sales invoice line.Amount])) AS Amount_, [Sales Invoice Header].[Bill-to Customer No_], [Sales Invoice Header].[Bill-to Name], [Sales Invoice Header].[selling season code], [Sales Invoice Header].[Shortcut Dimension 2 Code], [Sales Invoice Header].no_ AS InvoiceNo, [Sales Invoice Header].[posting date] AS DataFattura, [Geographical Zone].Description AS GeoZone1, [Geographical Zone_1].Description AS GeoZone2
FROM ([Sales Invoice Line] INNER JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) INNER JOIN ((Customer LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) ON [Sales Invoice Header].[Bill-to Customer No_] = Customer.No_
WHERE ((([Sales Invoice Line].Type)<>19 And ([Sales Invoice Line].Type)<>20 And ([Sales Invoice Line].Type)<>0))
GROUP BY [Sales Invoice Header].[Bill-to Customer No_], [Sales Invoice Header].[Bill-to Name], [Sales Invoice Header].[selling season code], [Sales Invoice Header].[Shortcut Dimension 2 Code], [Sales Invoice Header].no_, [Sales Invoice Header].[posting date], [Geographical Zone].Description, [Geographical Zone_1].Description
HAVING ((([Sales Invoice Header].[posting date]) Between [Forms]![Principale]![DataIniziale] And [Forms]![Principale]![DataFinale]));

